import React from "react";
import InfoPageLayout from "./InfoPageLayout";

const pageData = {
  title: "Careers",
  subtitle: "Join us in making the internet a safer place. We're looking for passionate people to help build the future of cybersecurity.",
  sections: [
    {
      title: "Why CyberVault?",
      description: "Work on challenging problems with smart, passionate people.",
      gridClass: "info-grid-2",
      grid: [
        {
          title: "Make an Impact",
          description: "Your work directly protects millions of users and organizations from cyber threats."
        },
        {
          title: "Learn & Grow",
          description: "Continuous learning opportunities, conferences, and professional development budget."
        },
        {
          title: "Great Culture",
          description: "Remote-first, inclusive environment with flexible hours and work-life balance."
        },
        {
          title: "Competitive Benefits",
          description: "Health, dental, equity, 401k matching, and unlimited PTO."
        }
      ]
    },
    {
      title: "Open Positions",
      description: "Find your next role in cybersecurity.",
      bgColor: "#f8fafc",
      gridClass: "jobs-grid",
      grid: [
        {
          title: "Senior Security Engineer",
          description: "Build and maintain our threat detection systems.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/security-engineer" }
        },
        {
          title: "Machine Learning Engineer",
          description: "Develop AI models for anomaly detection.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/ml-engineer" }
        },
        {
          title: "Frontend Engineer",
          description: "Build beautiful, secure user interfaces.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/frontend-engineer" }
        },
        {
          title: "Backend Engineer",
          description: "Scale our high-performance API infrastructure.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/backend-engineer" }
        },
        {
          title: "Product Manager",
          description: "Define the future of our security platform.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/product-manager" }
        },
        {
          title: "Security Researcher",
          description: "Discover and analyze emerging threats.",
          location: "Remote (US)",
          type: "Full-time",
          cta: { text: "Apply →", link: "/careers/security-researcher" }
        }
      ]
    },
    {
      title: "Our Hiring Process",
      description: "A transparent, respectful process that values your time.",
      content: "<ol><li><strong>Apply:</strong>Submit your resume and we'll review within 48 hours.</li><li><strong>Initial Call:</strong>30-minute call with our recruiting team.</li><li><strong>Technical Interview:</strong>Two technical interviews focused on relevant skills.</li><li><strong>Team Fit:</strong>Meet with team members and leadership.</li><li><strong>Offer:</strong>Competitive offer within one week.</li></ol>"
    }
  ],
  color: "#14b8a6"
};

function Careers() {
  return <InfoPageLayout {...pageData} />;
}

export default Careers;
